package org.eclipse.rdf4j.query.algebra.evaluation.optimizer.scope;

import static org.assertj.core.api.Assertions.assertThat;

import java.io.BufferedReader;
import java.io.InputStream;
import java.io.InputStreamReader;
import java.nio.charset.StandardCharsets;
import java.util.List;

import org.junit.jupiter.api.Test;

public class RewriteRuleCatalogTest {

	@Test
	public void productionCatalogIsCompleteAndMatchesRuleIds() throws Exception {
		InputStream resource = getClass().getResourceAsStream("/scope-safety/scope-rewrite-rules.csv");
		assertThat(resource).as("production scope rewrite rule catalog").isNotNull();
		List<String> rows;
		try (BufferedReader reader = new BufferedReader(
				new InputStreamReader(resource, StandardCharsets.UTF_8))) {
			rows = reader.lines().skip(1).filter(line -> !line.isBlank()).toList();
		}
		Class<?> ruleType = Class.forName(
				"org.eclipse.rdf4j.query.algebra.evaluation.optimizer.scope.RewriteRuleId");

		assertThat(rows).hasSize(28);
		assertThat(rows.stream().filter(row -> row.endsWith(",ALLOW"))).hasSize(15);
		assertThat(rows.stream().filter(row -> row.endsWith(",DENY"))).hasSize(13);
		assertThat(ruleType.getEnumConstants()).hasSize(28);
		assertThat(rows.stream().map(row -> row.substring(0, row.indexOf(','))).toList())
				.containsExactly(java.util.Arrays.stream(ruleType.getEnumConstants())
						.map(Object::toString)
						.toArray(String[]::new));
	}
}
